appsmith.onReady(() => {
  handleTouchpointsUpdate();
});
appsmith.onModelChange(() => {
  handleTouchpointsUpdate();
});
function handleTouchpointsUpdate() {
  // Note: ensure appsmith.model properties exist before reading
  const networkEvents = appsmith.model && appsmith.model.networkEvents ? appsmith.model.networkEvents : [];
  const scripts = appsmith.model && appsmith.model.scripts ? appsmith.model.scripts : {};
  const endpointList = document.getElementById('endpoint-list');
  const sdkList = document.getElementById('sdk-list');
  if (!endpointList || !sdkList) return;
  endpointList.innerHTML = "";
  sdkList.innerHTML = "";

  // Target arrays for categorization
  const aiIndicators = ["api.openai.com", "claude.ai", "mistral.ai", "vertex-ai", "huggingface", "revolut.com"];
  const unsanctionedAi = ["api.openai.com", "claude.ai", "mistral.ai"];

  // --- 1. Process Endpoints (Network Events) ---
  const observedEndpoints = new Set();
  let unsanctionedCount = 0;
  networkEvents.forEach(event => {
    if (event.method === "Network.requestWillBeSent" && event.params && event.params.request) {
      const urlStr = event.params.request.url;
      try {
        const domain = new URL(urlStr).hostname;
        if (aiIndicators.some(ai => domain.includes(ai))) {
          observedEndpoints.add(domain);
        }
      } catch (e) {}
    }
  });
  const endpointsArray = Array.from(observedEndpoints);
  endpointsArray.forEach(domain => {
    const isUnsanctioned = unsanctionedAi.some(ai => domain.includes(ai));
    if (isUnsanctioned) unsanctionedCount++;
    const statusClass = isUnsanctioned ? "critical" : "safe";
    const statusLabel = isUnsanctioned ? "Unsanctioned Signal" : "Audited Path";
    const icon = isUnsanctioned ? "⚠️" : "🌐";
    const div = document.createElement('div');
    div.className = 'list-item';
    div.innerHTML = `
            <div class="item-main">
                <div class="item-icon">${icon}</div>
                <div class="item-title">${domain}</div>
            </div>
            <div class="status-badge ${statusClass}">${statusLabel}</div>
        `;
    endpointList.appendChild(div);
  });
  if (endpointsArray.length === 0) {
    endpointList.innerHTML = `<div class="empty-state">No AI endpoints observed.</div>`;
  }

  // --- 2. Process SDKs/Libraries (Script Assets) ---
  const rootKey = Object.keys(scripts)[0];
  const scriptsMap = rootKey ? scripts[rootKey] : {};
  let sdkCount = 0;
  Object.entries(scriptsMap).forEach(([url, info]) => {
    const fileName = url.split('/').pop();
    if (fileName.includes("framework") || fileName.includes("main") || fileName.includes("app-")) {
      sdkCount++;
      const hasLeaks = info["sensitive PIIs"] && info["sensitive PIIs"].length > 0 || info.PIIs && info.PIIs.length > 0;
      const riskClass = hasLeaks ? "warning" : "safe";
      const riskLabel = hasLeaks ? "Active Exposure Risk" : "Observed Logic";
      const icon = "📦";
      const div = document.createElement('div');
      div.className = 'list-item';
      div.innerHTML = `
                <div class="item-main">
                    <div class="item-icon">${icon}</div>
                    <div class="item-title">${fileName}</div>
                </div>
                <div class="status-badge ${riskClass}">${riskLabel}</div>
            `;
      sdkList.appendChild(div);
    }
  });
  if (sdkCount === 0) {
    sdkList.innerHTML = `<div class="empty-state">No specific AI SDKs inferred.</div>`;
  }

  // --- 3. Update UI Metrics ---
  document.getElementById('endpoint-count').textContent = endpointsArray.length;
  document.getElementById('sdk-count').textContent = sdkCount;
  document.getElementById('unsanctioned-count').textContent = unsanctionedCount;
}

